import{f as e,D as E,o as a,c as h,a2 as l,b as i,w as r,a as n,G as d,a5 as s}from"./chunks/framework.Ccw_j35p.js";const P=JSON.parse('{"title":"进程与线程","description":"","frontmatter":{},"headers":[],"relativePath":"operating-system/process-thread/index.md","filePath":"operating-system/process-thread/index.md","lastUpdated":1780924966000}'),B={name:"operating-system/process-thread/index.md"};function g(A,t,p,u,b,c){const o=E("Mermaid");return a(),h("div",null,[t[4]||(t[4]=l('<h1 id="进程与线程" tabindex="-1">进程与线程 <a class="header-anchor" href="#进程与线程" aria-label="Permalink to &quot;进程与线程&quot;">​</a></h1><h2 id="⭐-面试重点速览" tabindex="-1">⭐ 面试重点速览 <a class="header-anchor" href="#⭐-面试重点速览" aria-label="Permalink to &quot;⭐ 面试重点速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>考点</th><th>频率</th><th>难度</th><th>考察方式</th></tr></thead><tbody><tr><td>进程 vs 线程区别</td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐</td><td>直接问区别，需要从多个维度回答</td></tr><tr><td>上下文切换开销</td><td>⭐⭐⭐⭐</td><td>⭐⭐⭐</td><td>问具体包含哪些操作，开销在哪里</td></tr><tr><td>用户态 vs 内核态</td><td>⭐⭐⭐⭐⭐</td><td>⭐⭐⭐</td><td>为什么需要两种状态，切换时机</td></tr><tr><td>并发 vs 并行</td><td>⭐⭐⭐⭐</td><td>⭐</td><td>概念区分，结合实际场景</td></tr><tr><td>多进程 vs 多线程选型</td><td>⭐⭐⭐</td><td>⭐⭐⭐⭐</td><td>架构设计题，看工程理解</td></tr></tbody></table><hr><h2 id="一、基本概念" tabindex="-1">一、基本概念 <a class="header-anchor" href="#一、基本概念" aria-label="Permalink to &quot;一、基本概念&quot;">​</a></h2><h3 id="什么是进程" tabindex="-1">什么是进程？ <a class="header-anchor" href="#什么是进程" aria-label="Permalink to &quot;什么是进程？&quot;">​</a></h3><p>进程（Process）是<strong>操作系统进行资源分配和调度的基本单位</strong>，是程序在计算机上的一次执行活动。</p><p>每个进程拥有独立的：</p><ul><li><strong>地址空间</strong>：独立的虚拟内存空间</li><li><strong>文件描述符表</strong>：打开的文件句柄</li><li><strong>信号处理</strong>：独立的信号处理函数</li><li><strong>进程控制块（PCB）</strong>：保存进程状态信息</li><li><strong>资源所有权</strong>：内存、文件、IO等资源</li></ul><h3 id="什么是线程" tabindex="-1">什么是线程？ <a class="header-anchor" href="#什么是线程" aria-label="Permalink to &quot;什么是线程？&quot;">​</a></h3><p>线程（Thread）是<strong>CPU调度的基本单位</strong>，也称为轻量级进程（LWP）。</p><p>线程共享进程的资源：</p><ul><li>同一个地址空间</li><li>同一个文件描述符表</li><li>相同的信号处理</li><li>共享堆内存</li></ul><p>每个线程拥有独立的：</p><ul><li><strong>程序计数器（PC）</strong>：记录下一条指令地址</li><li><strong>栈空间</strong>：保存局部变量和返回地址</li><li><strong>寄存器集合</strong>：保存CPU寄存器状态</li><li><strong>线程控制块（TCB）</strong>：保存线程状态</li></ul><h3 id="进程-vs-线程-对比" tabindex="-1">进程 vs 线程 对比 <a class="header-anchor" href="#进程-vs-线程-对比" aria-label="Permalink to &quot;进程 vs 线程 对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>对比维度</th><th>进程</th><th>线程</th></tr></thead><tbody><tr><td>资源分配</td><td>资源分配单位，拥有独立地址空间</td><td>CPU调度单位，共享进程地址空间</td></tr><tr><td>切换开销</td><td>大（需要切换页表、刷新TLB）</td><td>小（只需要切换寄存器和栈）</td></tr><tr><td>通信方式</td><td>需要IPC（进程间通信）</td><td>直接读写共享内存</td></tr><tr><td>并发性</td><td>多进程可以真正并行</td><td>多线程也可以并行</td></tr><tr><td>安全性</td><td>一个进程崩溃不影响其他进程</td><td>一个线程崩溃会导致整个进程崩溃</td></tr><tr><td>系统调用</td><td>更多页表操作，TLB失效</td><td>更少，共享页表</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">相关阅读</p><p>Java中的线程实现参见：<a href="./../../java-advanced/concurrency/">Java 并发编程</a> JVM中的线程模型参见：<a href="./../../java-advanced/jvm/memory-model">JVM 内存模型</a></p></div><hr><h2 id="二、上下文切换" tabindex="-1">二、上下文切换 <a class="header-anchor" href="#二、上下文切换" aria-label="Permalink to &quot;二、上下文切换&quot;">​</a></h2><h3 id="什么是上下文切换" tabindex="-1">什么是上下文切换？ <a class="header-anchor" href="#什么是上下文切换" aria-label="Permalink to &quot;什么是上下文切换？&quot;">​</a></h3><p>上下文切换（Context Switch）是指CPU从一个进程/线程切换到另一个进程/线程时，保存当前状态并加载新状态的过程。</p><h3 id="上下文切换的完整流程" tabindex="-1">上下文切换的完整流程 <a class="header-anchor" href="#上下文切换的完整流程" aria-label="Permalink to &quot;上下文切换的完整流程&quot;">​</a></h3>',23)),(a(),i(s,null,{default:r(()=>[d(o,{id:"mermaid-296",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20A%5B%E5%BD%93%E5%89%8D%E8%BF%9B%E7%A8%8B%2F%E7%BA%BF%E7%A8%8B%E8%BF%90%E8%A1%8C%5D%20--%3E%20B%5B%E8%A7%A6%E5%8F%91%E4%B8%AD%E6%96%AD%2F%E7%B3%BB%E7%BB%9F%E8%B0%83%E7%94%A8%5D%0A%20%20%20%20B%20--%3E%20C%5B%E4%BF%9D%E5%AD%98CPU%E5%AF%84%E5%AD%98%E5%99%A8%E5%88%B0PCB%2FTCB%5D%0A%20%20%20%20C%20--%3E%20D%5B%E6%9B%B4%E6%96%B0%E8%BF%9B%E7%A8%8B%E7%8A%B6%E6%80%81%E4%B8%BA%E5%B0%B1%E7%BB%AA%2F%E9%98%BB%E5%A1%9E%5D%0A%20%20%20%20D%20--%3E%20E%5B%E8%B0%83%E5%BA%A6%E5%99%A8%E9%80%89%E6%8B%A9%E4%B8%8B%E4%B8%80%E4%B8%AA%E8%BF%9B%E7%A8%8B%5D%0A%20%20%20%20E%20--%3E%20F%5B%E6%9B%B4%E6%96%B0%E6%96%B0%E8%BF%9B%E7%A8%8B%E7%8A%B6%E6%80%81%E4%B8%BA%E8%BF%90%E8%A1%8C%5D%0A%20%20%20%20F%20--%3E%20G%5B%E6%81%A2%E5%A4%8D%E6%96%B0%E8%BF%9B%E7%A8%8B%E7%9A%84%E5%AF%84%E5%AD%98%E5%99%A8%5D%0A%20%20%20%20G%20--%3E%20H%5B%E5%88%B7%E6%96%B0TLB%EF%BC%88%E8%BF%9B%E7%A8%8B%E5%88%87%E6%8D%A2%E6%89%8D%E9%9C%80%E8%A6%81%EF%BC%89%5D%0A%20%20%20%20H%20--%3E%20I%5B%E5%BC%80%E5%A7%8B%E6%89%A7%E8%A1%8C%E6%96%B0%E8%BF%9B%E7%A8%8B%5D%0A"})]),fallback:r(()=>[...t[0]||(t[0]=[n(" Loading... ",-1)])]),_:1})),t[5]||(t[5]=l('<h3 id="切换的具体开销" tabindex="-1">切换的具体开销 <a class="header-anchor" href="#切换的具体开销" aria-label="Permalink to &quot;切换的具体开销&quot;">​</a></h3><table tabindex="0"><thead><tr><th>切换类型</th><th>保存内容</th><th>刷新操作</th><th>开销</th></tr></thead><tbody><tr><td>进程切换</td><td>PCB + 页表基址</td><td>需要刷新TLB</td><td>~1000-1500 时钟周期</td></tr><tr><td>线程切换（同进程）</td><td>TCB + 寄存器</td><td>不需要刷新TLB</td><td>~100-300 时钟周期</td></tr><tr><td>线程切换（跨进程）</td><td>同进程切换</td><td>需要刷新TLB</td><td>同进程切换开销</td></tr></tbody></table><h3 id="哪些操作会触发上下文切换" tabindex="-1">哪些操作会触发上下文切换？ <a class="header-anchor" href="#哪些操作会触发上下文切换" aria-label="Permalink to &quot;哪些操作会触发上下文切换？&quot;">​</a></h3><ol><li><strong>中断处理</strong>：硬件中断，定时器到了</li><li><strong>系统调用</strong>：用户程序陷入内核</li><li><strong>进程调度</strong>：当前进程时间片用完</li><li><strong>进程阻塞</strong>：等待IO、等待锁</li><li><strong>唤醒抢占</strong>：高优先级进程抢占CPU</li></ol><div class="warning custom-block"><p class="custom-block-title">TLB 刷新开销</p><p>进程切换时，因为地址空间不同，TLB中缓存的页表项会失效，需要全部刷新。这是进程切换最大的开销来源。线程切换共享同一个地址空间，TLB不需要刷新，所以快很多。</p></div><hr><h2 id="三、用户态-vs-内核态" tabindex="-1">三、用户态 vs 内核态 <a class="header-anchor" href="#三、用户态-vs-内核态" aria-label="Permalink to &quot;三、用户态 vs 内核态&quot;">​</a></h2><h3 id="为什么需要两种特权级" tabindex="-1">为什么需要两种特权级？ <a class="header-anchor" href="#为什么需要两种特权级" aria-label="Permalink to &quot;为什么需要两种特权级？&quot;">​</a></h3><p>为了<strong>隔离</strong>和<strong>保护</strong>：</p><ul><li>内核掌握系统资源，需要保护不被用户程序随意修改</li><li>用户程序出错时，不会影响内核和其他进程</li><li>防止用户程序直接操作硬件，保证系统安全</li></ul><h3 id="特权级分级-x86" tabindex="-1">特权级分级（x86） <a class="header-anchor" href="#特权级分级-x86" aria-label="Permalink to &quot;特权级分级（x86）&quot;">​</a></h3><p>x86 CPU 有 4 个特权级（Ring 0 ~ Ring 3）：</p><ul><li><strong>Ring 0</strong>：内核态，可以执行所有指令，访问所有地址</li><li><strong>Ring 1 ~ Ring 2</strong>：未使用，保留</li><li><strong>Ring 3</strong>：用户态，只能访问受限资源，不能直接访问硬件</li></ul><h3 id="用户态到内核态的切换时机" tabindex="-1">用户态到内核态的切换时机 <a class="header-anchor" href="#用户态到内核态的切换时机" aria-label="Permalink to &quot;用户态到内核态的切换时机&quot;">​</a></h3><p>三种方式会触发切换：</p><ol><li><p><strong>系统调用（System Call）</strong></p><ul><li>用户程序主动请求内核服务</li><li>例如：read()、write()、malloc() 扩展堆</li></ul></li><li><p><strong>中断（Interrupt）</strong></p><ul><li>IO设备完成操作，通知CPU</li><li>例如：磁盘读完成、键盘输入</li></ul></li><li><p><strong>异常（Exception）</strong></p><ul><li>CPU执行过程中遇到错误</li><li>例如：缺页异常、除零错误</li></ul></li></ol>',16)),(a(),i(s,null,{default:r(()=>[d(o,{id:"mermaid-506",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20U%20as%20%E7%94%A8%E6%88%B7%E6%80%81%0A%20%20%20%20participant%20K%20as%20%E5%86%85%E6%A0%B8%E6%80%81%0A%20%20%20%20U-%3E%3EK%3A%20%E8%A7%A6%E5%8F%91%E7%B3%BB%E7%BB%9F%E8%B0%83%E7%94%A8%2F%E4%B8%AD%E6%96%AD%2F%E5%BC%82%E5%B8%B8%0A%20%20%20%20Note%20over%20K%3A%20%E4%BF%9D%E5%AD%98%E7%94%A8%E6%88%B7%E6%A0%88%E5%AF%84%E5%AD%98%E5%99%A8%3Cbr%2F%3E%E5%88%87%E6%8D%A2%E5%88%B0%E5%86%85%E6%A0%B8%E6%A0%88%3Cbr%2F%3E%E6%89%A7%E8%A1%8C%E5%AF%B9%E5%BA%94%E7%9A%84%E5%A4%84%E7%90%86%E5%87%BD%E6%95%B0%0A%20%20%20%20K-%3E%3EU%3A%20%E5%A4%84%E7%90%86%E5%AE%8C%E6%88%90%EF%BC%8C%E6%81%A2%E5%A4%8D%E7%94%A8%E6%88%B7%E6%80%81%0A"})]),fallback:r(()=>[...t[1]||(t[1]=[n(" Loading... ",-1)])]),_:1})),t[6]||(t[6]=l('<h3 id="系统调用-vs-中断的区别" tabindex="-1">系统调用 vs 中断的区别 <a class="header-anchor" href="#系统调用-vs-中断的区别" aria-label="Permalink to &quot;系统调用 vs 中断的区别&quot;">​</a></h3><table tabindex="0"><thead><tr><th>对比</th><th>系统调用</th><th>中断</th></tr></thead><tbody><tr><td>触发时机</td><td><strong>同步</strong>，用户程序主动请求</td><td><strong>异步</strong>，硬件异步通知</td></tr><tr><td>上下文</td><td>同一个进程上下文</td><td>通常切入当前进程上下文</td></tr><tr><td>返回方式</td><td>回到调用者下一条指令</td><td>回到被中断的地方继续执行</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">相关阅读</p><p>Java NIO中涉及大量系统调用，参见：<a href="./../../java-advanced/io-nio/nio">Java NIO</a></p></div><hr><h2 id="四、并发-vs-并行" tabindex="-1">四、并发 vs 并行 <a class="header-anchor" href="#四、并发-vs-并行" aria-label="Permalink to &quot;四、并发 vs 并行&quot;">​</a></h2><h3 id="基本概念" tabindex="-1">基本概念 <a class="header-anchor" href="#基本概念" aria-label="Permalink to &quot;基本概念&quot;">​</a></h3><ul><li><strong>并发（Concurrency）</strong>：多个任务在<strong>同一时间段内</strong>交替执行，宏观上同时进行，微观上串行。</li><li><strong>并行（Parallelism）</strong>：多个任务在<strong>同一时刻</strong>同时执行，需要多个CPU核心。</li></ul><h3 id="图解对比" tabindex="-1">图解对比 <a class="header-anchor" href="#图解对比" aria-label="Permalink to &quot;图解对比&quot;">​</a></h3>',8)),(a(),i(s,null,{default:r(()=>[d(o,{id:"mermaid-587",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20subgraph%20%E5%B9%B6%E5%8F%91%20Concurrent%0A%20%20%20%20direction%20LR%0A%20%20%20%20T1%5BTask%201%5D%20---%20T2%5BTask%202%5D%20---%20T1%20---%20T2%20---%20T1%0A%20%20%20%20end%0A%20%20%20%20subgraph%20%E5%B9%B6%E8%A1%8C%20Parallel%0A%20%20%20%20direction%20LR%0A%20%20%20%20Core1%3A%20T1%20T1%20T1%20T1%0A%20%20%20%20Core2%3A%20T2%20T2%20T2%20T2%0A%20%20%20%20end%0A"})]),fallback:r(()=>[...t[2]||(t[2]=[n(" Loading... ",-1)])]),_:1})),t[7]||(t[7]=l('<h3 id="实际场景举例" tabindex="-1">实际场景举例 <a class="header-anchor" href="#实际场景举例" aria-label="Permalink to &quot;实际场景举例&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>并发</th><th>并行</th></tr></thead><tbody><tr><td>单CPU核心跑多个线程</td><td>✓</td><td>✗</td></tr><tr><td>多CPU核心跑多个线程</td><td>✓</td><td>✓</td></tr><tr><td>Node.js单线程处理多个请求</td><td>✓ (事件驱动)</td><td>✗</td></tr><tr><td>Tomcat线程池处理请求</td><td>✓</td><td>✓ (多核心)</td></tr></tbody></table><h3 id="并发解决什么问题" tabindex="-1">并发解决什么问题？ <a class="header-anchor" href="#并发解决什么问题" aria-label="Permalink to &quot;并发解决什么问题？&quot;">​</a></h3><ol><li><p><strong>IO密集型</strong>：大部分时间等IO，CPU闲着想干活</p><ul><li>比如：Web服务器处理请求，大部分时间等数据库</li><li>并发可以让CPU在等IO的时候处理其他请求</li><li>提高CPU利用率</li></ul></li><li><p><strong>提升响应性</strong>：后台任务不阻塞用户交互</p><ul><li>比如：UI线程响应用户点击，后台线程处理计算</li></ul></li></ol><h3 id="并行解决什么问题" tabindex="-1">并行解决什么问题？ <a class="header-anchor" href="#并行解决什么问题" aria-label="Permalink to &quot;并行解决什么问题？&quot;">​</a></h3><ol><li><strong>CPU密集型</strong>：利用多核心加速计算 <ul><li>比如：视频编码、大数据处理</li><li>分而治之，MapReduce</li></ul></li></ol><hr><h2 id="五、进程的三种基本状态" tabindex="-1">五、进程的三种基本状态 <a class="header-anchor" href="#五、进程的三种基本状态" aria-label="Permalink to &quot;五、进程的三种基本状态&quot;">​</a></h2>',8)),(a(),i(s,null,{default:r(()=>[d(o,{id:"mermaid-717",class:"mermaid",graph:"stateDiagram-v2%0A%20%20%20%20%5B*%5D%20--%3E%20%E5%B0%B1%E7%BB%AA%0A%20%20%20%20%E5%B0%B1%E7%BB%AA%20--%3E%20%E8%BF%90%E8%A1%8C%3A%20%E8%B0%83%E5%BA%A6%E5%99%A8%E9%80%89%E4%B8%AD%0A%20%20%20%20%E8%BF%90%E8%A1%8C%20--%3E%20%E5%B0%B1%E7%BB%AA%3A%20%E6%97%B6%E9%97%B4%E7%89%87%E7%94%A8%E5%AE%8C%3Cbr%2F%3E%E9%AB%98%E4%BC%98%E5%85%88%E7%BA%A7%E8%BF%9B%E7%A8%8B%E6%8A%A2%E5%8D%A0%0A%20%20%20%20%E8%BF%90%E8%A1%8C%20--%3E%20%E9%98%BB%E5%A1%9E%3A%20%E7%AD%89%E5%BE%85%E4%BA%8B%E4%BB%B6%3Cbr%2F%3E%E7%AD%89%E5%BE%85IO%E3%80%81%E7%AD%89%E5%BE%85%E9%94%81%0A%20%20%20%20%E9%98%BB%E5%A1%9E%20--%3E%20%E5%B0%B1%E7%BB%AA%3A%20%E4%BA%8B%E4%BB%B6%E5%8F%91%E7%94%9F%3Cbr%2F%3EIO%E5%AE%8C%E6%88%90%E3%80%81%E8%8E%B7%E5%BE%97%E9%94%81%0A%20%20%20%20%E8%BF%90%E8%A1%8C%20--%3E%20%5B*%5D%3A%20%E8%BF%9B%E7%A8%8B%E7%BB%93%E6%9D%9F%0A"})]),fallback:r(()=>[...t[3]||(t[3]=[n(" Loading... ",-1)])]),_:1})),t[8]||(t[8]=l('<ul><li><strong>就绪状态</strong>：进程已获得除CPU外的一切资源，等待分配CPU</li><li><strong>运行状态</strong>：进程正在CPU上执行</li><li><strong>阻塞状态</strong>：进程等待某事件发生，暂时无法运行（即使CPU空闲也不能运行）</li></ul><hr><h2 id="六、面试高频题" tabindex="-1">六、面试高频题 <a class="header-anchor" href="#六、面试高频题" aria-label="Permalink to &quot;六、面试高频题&quot;">​</a></h2><h3 id="q1-进程和线程的区别-为什么要有线程" tabindex="-1">Q1: 进程和线程的区别？为什么要有线程？ <a class="header-anchor" href="#q1-进程和线程的区别-为什么要有线程" aria-label="Permalink to &quot;Q1: 进程和线程的区别？为什么要有线程？&quot;">​</a></h3><p><strong>标准答案：</strong></p><p><strong>区别：</strong></p><ol><li>进程是资源分配的基本单位，线程是CPU调度的基本单位</li><li>进程有独立的地址空间，线程共享进程的地址空间</li><li>进程切换开销大，需要刷新TLB；线程切换开销小，不需要刷新TLB</li><li>进程间通信需要特殊机制（IPC），线程可以直接读写共享内存</li><li>一个进程崩溃不影响其他进程，一个线程崩溃会导致整个进程崩溃</li></ol><p><strong>为什么需要线程：</strong></p><ol><li><strong>并发更高效</strong>：创建一个线程比创建进程快得多</li><li><strong>切换开销小</strong>：线程切换比进程切换开销小一个数量级</li><li><strong>通信更方便</strong>：共享内存，不需要内核介入</li><li><strong>更好利用多核</strong>：多线程可以并行在多个核心上</li></ol><p><strong>背景：</strong> 在多线程出现之前，一个进程同一时刻只能做一件事。如果需要同时做多件事（边下载边显示边保存），就必须多进程，开销太大。线程让一个进程内部也能并发执行多个任务。</p><hr><h3 id="q2-上下文切换具体做了哪些事情-开销在哪里" tabindex="-1">Q2: 上下文切换具体做了哪些事情？开销在哪里？ <a class="header-anchor" href="#q2-上下文切换具体做了哪些事情-开销在哪里" aria-label="Permalink to &quot;Q2: 上下文切换具体做了哪些事情？开销在哪里？&quot;">​</a></h3><p><strong>标准答案：</strong></p><p><strong>具体步骤：</strong></p><ol><li>暂停当前进程/线程，把CPU寄存器的值保存到PCB/TCB中</li><li>更新进程状态（从运行变为就绪/阻塞）</li><li>调度器根据算法选择下一个要运行的进程</li><li>恢复新进程的寄存器上下文</li><li><strong>如果是进程切换</strong>：需要加载新的页表基址（CR3寄存器），刷新TLB</li><li>开始执行新进程</li></ol><p><strong>主要开销：</strong></p><ol><li><strong>直接开销</strong>：保存和恢复寄存器、PCB/TCB操作，大约几百个时钟周期</li><li><strong>间接开销</strong>：进程切换导致TLB刷新，重新建立TLB缓存，这是最大开销</li><li><strong>缓存影响</strong>：新进程会冲刷原进程的CPU缓存命中率</li></ol><p><strong>线程切换比进程切换快在哪里？</strong> 同进程内的线程切换共享同一个地址空间，不需要修改页表，不需要刷新TLB，所以快5~10倍。</p><hr><h3 id="q3-什么时候从用户态切换到内核态" tabindex="-1">Q3: 什么时候从用户态切换到内核态？ <a class="header-anchor" href="#q3-什么时候从用户态切换到内核态" aria-label="Permalink to &quot;Q3: 什么时候从用户态切换到内核态？&quot;">​</a></h3><p><strong>标准答案：</strong></p><p>三种情况：</p><ol><li><p><strong>系统调用</strong>：用户程序主动请求内核服务，比如读写文件、分配内存、创建线程。这是<strong>同步</strong>的，用户主动发起。</p></li><li><p><strong>中断</strong>：IO设备完成操作后，发中断信号给CPU，CPU暂停当前程序去处理中断。比如磁盘读完成、网络包到达、键盘输入。这是<strong>异步</strong>的，硬件主动发起。</p></li><li><p><strong>异常</strong>：CPU执行过程中遇到错误，比如缺页异常（page fault）、除零错误、非法指令。CPU会陷入内核处理错误。</p></li></ol><p>系统调用本质上也是通过中断实现的（x86上是 <code>int 0x80</code> 指令），但它是用户主动请求，和异步硬件中断不同。</p><hr><h3 id="q4-并发和并行的区别-举个实际例子。" tabindex="-1">Q4: 并发和并行的区别？举个实际例子。 <a class="header-anchor" href="#q4-并发和并行的区别-举个实际例子。" aria-label="Permalink to &quot;Q4: 并发和并行的区别？举个实际例子。&quot;">​</a></h3><p><strong>标准答案：</strong></p><p><strong>并发</strong>是多个任务<strong>在同一时间段内</strong>交替执行，宏观上同时进行，微观上还是串行。比如单CPU核心通过时间片轮转跑多个线程，就是并发。</p><p><strong>并行</strong>是多个任务<strong>在同一时刻</strong>同时执行，必须要有多个CPU核心才能实现。比如两个线程分别跑在两个核心上，就是并行。</p><p><strong>例子：</strong></p><ul><li>你吃饭吃到一半，电话来了，你停下来去接电话，接完继续吃饭，这是<strong>并发</strong>（处理多件事，交替进行）</li><li>你吃饭吃到一半，电话来了，你一边吃饭一边接电话，这是<strong>并行</strong>（同时处理多件事）</li></ul><p><strong>工程应用：</strong></p><ul><li>Web服务器处理请求，用多线程/事件驱动，本质是并发，提高CPU利用率（利用等IO的间隙处理其他请求）</li><li>视频编码，用多线程分块编码，利用多核心，这是并行，加快整体速度</li></ul><hr><h3 id="q5-多进程和多线程该怎么选" tabindex="-1">Q5: 多进程和多线程该怎么选？ <a class="header-anchor" href="#q5-多进程和多线程该怎么选" aria-label="Permalink to &quot;Q5: 多进程和多线程该怎么选？&quot;">​</a></h3><p><strong>标准答案：</strong></p><p><strong>选择多进程的场景：</strong></p><ol><li><strong>稳定性要求高</strong>：一个进程挂了不影响其他进程，比如Nginx的worker进程模型、Chrome的多进程架构</li><li><strong>隔离性要求</strong>：不同服务需要隔离地址空间，防止互相干扰</li><li><strong>利用多核+稳定优先</strong>：比如后端服务，一个进程处理一个端口，挂了其他进程还能工作</li><li><strong>用不上共享内存</strong>：任务之间不需要大量共享数据，通信少</li></ol><p><strong>选择多线程的场景：</strong></p><ol><li><strong>需要共享数据</strong>：任务之间需要频繁共享大量数据，用线程共享内存比IPC方便</li><li><strong>追求性能</strong>：创建和切换开销小，高并发场景更适合，比如Tomcat的线程池模型</li><li><strong>IO密集型任务</strong>：需要大量并发等待IO，线程更轻量</li><li>Java生态默认就是多线程，JVM本身就是多线程模型</li></ol><p><strong>现代趋势：</strong> 协程（用户态线程）正在变得越来越流行，比线程更轻量，切换开销更小，适合超高并发场景。Go语言原生支持协程。</p><hr><h3 id="q6-什么是重入-线程安全和可重入的区别" tabindex="-1">Q6: 什么是重入？线程安全和可重入的区别？ <a class="header-anchor" href="#q6-什么是重入-线程安全和可重入的区别" aria-label="Permalink to &quot;Q6: 什么是重入？线程安全和可重入的区别？&quot;">​</a></h3><p><strong>标准答案：</strong></p><p><strong>可重入函数</strong>：指一个函数可以被多个线程安全地重复调用，即使在调用过程中被打断，再次进入也不会出错。可重入要求：</p><ul><li>不使用静态/全局的非const变量</li><li>不返回静态/全局变量的地址</li><li>只使用调用者提供的数据</li><li>不调用不可重入函数</li></ul><p><strong>区别：</strong></p><ul><li>可重入：一定线程安全，因为靠调用者提供的数据，没有共享状态</li><li>线程安全：不一定可重入，线程安全可能用了锁保护全局状态，如果锁已经被当前线程持有了，重入可能会死锁</li><li>比如：用了互斥锁保护的函数，不一定是可重入的</li></ul>',48))])}const m=e(B,[["render",g]]);export{P as __pageData,m as default};
